    #[test]
    fn test_x25519_rfc7748_vectors() {
        // RFC 7748 Section 6.1 test vectors
        let alice_private = hex::decode("...").unwrap();
        let bob_public = hex::decode("...").unwrap();
        let expected_shared = hex::decode("...").unwrap();

        let alice = X25519KeyPair::from_bytes(&alice_private).unwrap();
        let bob_pk = X25519PublicKey::from_bytes(&bob_public).unwrap();

